class Solution:
    def hasTrailingZeros(self, nums):
        n = len(nums)
        for i in range(n):
            for j in range(i + 1, n):
                if (nums[i] | nums[j]) % 2 == 0:
                    return True
        return False

solutions.python:
class Solution:
    def hasTrailingZeros(self, nums: List[int]) -> bool:
        evens = sum(1 for x in nums if x % 2 == 0)
        return evens >= 2

